560→/**
561→ * 下载进度卡片组件
562→ */
563→@Composable
564→private fun DownloadProgressCard(
565→    task: DownloadTask,
566→    onCancel: () -> Unit,
567→    formatFileSize: (Long) -> String,
568→    formatSpeed: (Long) -> String,
569→    formatRemainingTime: (Long) -> String,
570→    getStatusText: (DownloadStatus) -> String
571→) {
572→    Card(
573→        modifier = Modifier.fillMaxWidth(),
574→        colors = CardDefaults.cardColors(
575→            containerColor = when (task.status) {
576→                DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.errorContainer
577→                DownloadStatus.WAITING_FOR_AUTH -> MaterialTheme.colorScheme.tertiaryContainer
578→                else -> MaterialTheme.colorScheme.primaryContainer
579→            }
580→        )
581→    ) {
582→        Column(modifier = Modifier.padding(16.dp)) {
583→            // 标题和状态
584→            Row(
585→                modifier = Modifier.fillMaxWidth(),
586→                horizontalArrangement = Arrangement.SpaceBetween,
587→                verticalAlignment = Alignment.CenterVertically
588→            ) {
589→                Column(Modifier.weight(1f)) {
590→                    Text(
591→                        task.title,
592→                        style = MaterialTheme.typography.titleSmall,
593→                        maxLines = 1,
594→                        overflow = TextOverflow.Ellipsis
595→                    )
596→                    Text(
597→                        getStatusText(task.status),
598→                        style = MaterialTheme.typography.bodySmall,
599→                        color = when (task.status) {
600→                            DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.error
601→                            DownloadStatus.WAITING_FOR_AUTH -> MaterialTheme.colorScheme.onTertiaryContainer
602→                            else -> MaterialTheme.colorScheme.onPrimaryContainer
603→                        }
604→                    )
605→                }
606→
607→                // 取消按钮
608→                if (task.status == DownloadStatus.DOWNLOADING || task.status == DownloadStatus.FETCHING_INFO) {
609→                    IconButton(onClick = onCancel) {
610→                        Icon(Icons.Default.Close, "取消", tint = MaterialTheme.colorScheme.error)
611→                    }
612→                }
613→            }
614→
615→            Spacer(Modifier.height(12.dp))
616→
617→            // 进度条
618→            if (task.status == DownloadStatus.DOWNLOADING) {
619→                Column {
620→                    Row(
621→                        modifier = Modifier.fillMaxWidth(),
622→                        horizontalArrangement = Arrangement.SpaceBetween
623→                    ) {
624→                        Text(
625→                            "${task.progress}%",
626→                            style = MaterialTheme.typography.bodySmall
627→                        )
628→                        if (task.speed > 0) {
629→                            Text(
630→                                formatSpeed(task.speed),
631→                                style = MaterialTheme.typography.bodySmall,
632→                                color = MaterialTheme.colorScheme.primary
633→                            )
634→                        }
635→                    }
636→
637→                    Spacer(Modifier.height(4.dp))
638→
639→                    LinearProgressIndicator(
640→                        progress = { task.progress / 100f },
641→                        modifier = Modifier.fillMaxWidth(),
642→                        color = MaterialTheme.colorScheme.primary
643→                    )
644→
645→                    // 文件大小和剩余时间
646→                    if (task.totalBytes > 0) {
647→                        Spacer(Modifier.height(4.dp))
648→                        Row(
649→                            modifier = Modifier.fillMaxWidth(),
650→                            horizontalArrangement = Arrangement.SpaceBetween
651→                        ) {
652→                            Text(
653→                                "${formatFileSize(task.bytesDownloaded)} / ${formatFileSize(task.totalBytes)}",
654→                                style = MaterialTheme.typography.bodySmall,
655→                                color = MaterialTheme.colorScheme.onPrimaryContainer
656→                            )
657→                            if (task.remainingTime > 0 && task.speed > 0) {
658→                                Text(
659→                                    "剩余 ${formatRemainingTime(task.remainingTime)}",
660→                                    style = MaterialTheme.typography.bodySmall,
661→                                    color = MaterialTheme.colorScheme.onPrimaryContainer
662→                                )
663→                            }
664→                        }
665→                    }
666→                }
667→            } else if (task.status == DownloadStatus.FETCHING_INFO) {
668→                Row(
669→                    modifier = Modifier.fillMaxWidth(),
670→                    verticalAlignment = Alignment.CenterVertically
671→                ) {
672→                    CircularProgressIndicator(
673→                        modifier = Modifier.size(20.dp),
674→                        strokeWidth = 2.dp
675→                    )
676→                    Spacer(Modifier.width(8.dp))
677→                    Text(
678→                        "正在解析视频信息...",
679→                        style = MaterialTheme.typography.bodySmall,
680→                        color = MaterialTheme.colorScheme.onPrimaryContainer
681→                    )
682→                }
683→            } else if (task.status == DownloadStatus.FAILED) {
684→                Row(
685→                    modifier = Modifier.fillMaxWidth(),
686→                    verticalAlignment = Alignment.CenterVertically
687→                ) {
688→                    Icon(
689→                        Icons.Default.Error,
690→                        contentDescription = null,
691→                        tint = MaterialTheme.colorScheme.error,
692→                        modifier = Modifier.size(20.dp)
693→                    )
694→                    Spacer(Modifier.width(8.dp))
695→                    Text(
696→                        task.errorMessage ?: "下载失败",
697→                        style = MaterialTheme.typography.bodySmall,
698→                        color = MaterialTheme.colorScheme.error
699→                    )
700→                }
701→            } else if (task.status == DownloadStatus.COMPLETED) {
702→                Row(
703→                    modifier = Modifier.fillMaxWidth(),
704→                    verticalAlignment = Alignment.CenterVertically
705→                ) {
706→                    Icon(
707→                        Icons.Default.CheckCircle,
708→                        contentDescription = null,
709→                        tint = MaterialTheme.colorScheme.primary,
710→                        modifier = Modifier.size(20.dp)
711→                    )
712→                    Spacer(Modifier.width(8.dp))
713→                    Text(
714→                        "下载完成",
715→                        style = MaterialTheme.typography.bodySmall,
716→                        color = MaterialTheme.colorScheme.primary
717→                    )
718→                }
719→            } else if (task.status == DownloadStatus.WAITING_FOR_AUTH) {
720→                Row(
721→                    modifier = Modifier.fillMaxWidth(),
722→                    verticalAlignment = Alignment.CenterVertically
723→                ) {
724→                    Icon(
725→                        Icons.Default.Lock,
726→                        contentDescription = null,
727→                        tint = MaterialTheme.colorScheme.tertiary,
728→                        modifier = Modifier.size(20.dp)
729→                    )
730→                    Spacer(Modifier.width(8.dp))
731→                    Text(
732→                        "需要登录获取下载权限",
733→                        style = MaterialTheme.typography.bodySmall,
734→                        color = MaterialTheme.colorScheme.onTertiaryContainer
735→                    )
736→                }
737→            }
738→        }
739→    }
740→}
