    /**
     * 从历史记录中删除条目并删除视频文件（通过 filePath）
     */
    fun deleteFromHistoryByPath(filePath: String) {
        viewModelScope.launch(Dispatchers.IO) {
            // 查找历史记录
            val history = _downloadHistory.value.find { it.filePath == filePath }
            if (history != null) {
                // 删除视频文件
                try {
                    val videoFile = File(history.filePath)
                    if (videoFile.exists()) {
                        videoFile.delete()
                        android.util.Log.d("HomeViewModel", "Deleted video file: ${history.filePath}")
                    }

                    // 删除相关字幕文件
                    val base = history.filePath.substringBeforeLast(".")
                    listOf(".vtt", ".wordts.json").forEach { ext ->
                        val file = File("$base$ext")
                        if (file.exists()) {
                            file.delete()
                        }
                    }
                } catch (e: Exception) {
                    android.util.Log.e("HomeViewModel", "Error deleting video file", e)
                }

                // 从历史记录中移除
                _downloadHistory.update { it.filter { h -> h.id != history.id } }
                saveDownloadHistory()
            }
        }
    }

