        }
    }

    // ========== TikTok ==========

    fun onTiktokCookiesExtracted(
        cookies: Map<String, String>,
        fullCookie: String = "",
        onComplete: (String, String?) -> Unit
    ) {
        viewModelScope.launch {
            val cookieString = if (fullCookie.isNotBlank()) fullCookie else {
                cookies.entries.joinToString("; ") { "${it.key}=${it.value}" }
            }

            // 保存关键字段
            cookies["sessionid"]?.let { videoConfigStore.setTiktokSessionid(it) }
