            if (pendingUrl.isNotBlank()) {
                _uiState.update { it.copy(pendingDownloadUrl = "") }
                downloadVideo(onComplete)
            }
        }
    }

    fun dismissTiktokLogin() {
        _uiState.update {
            it.copy(
                showTiktokLogin = false,
                pendingDownloadUrl = ""
            )
        }
        // 移除等待认证的任务
        activeDownloadTasks.entries.find { it.value.status == DownloadStatus.WAITING_FOR_AUTH }?.key?.let { taskId ->
            activeDownloadTasks.remove(taskId)
            updateActiveDownloads()
        }
    }

    // ========== 转录队列状态 ==========

    /**
     * 更新转录队列状态
     */
    fun updateTranscriptionQueue(
        currentVideo: String?,
        queueList: List<String>,
        progress: Int,
        message: String
    ) {
        _uiState.update {
            it.copy(
                transcribingVideo = currentVideo,
                transcriptionQueue = queueList,
                transcriptionProgress = progress,
                transcriptionMessage = message
            )
        }
    }

    /**
     * 转录完成，清除状态并更新数据库中的 vttPath
     */
    fun transcriptionCompleted(videoPath: String? = null, vttPath: String? = null) {
        val isSuccess = videoPath != null && vttPath != null
        _uiState.update {
            it.copy(
                transcribingVideo = null,
                transcriptionQueue = emptyList(),
                transcriptionProgress = 0,
                transcriptionMessage = "",
                snackbarMessage = if (isSuccess) "转录完成，可以开始学习了" else "转录失败，请检查网络和 API Key",
                switchToTab = if (isSuccess) 2 else null
            )
        }
        // 更新数据库中的 vttPath
        if (videoPath != null && vttPath != null) {
            viewModelScope.launch(Dispatchers.IO) {
                try {
                    val video = videoRepository.getByPath(videoPath)
                    if (video != null) {
                        val wtsPath = vttPath.substringBeforeLast(".") + ".wordts.json"
                        videoRepository.update(video.copy(
                            vttPath = vttPath,
                            wordTsPath = if (java.io.File(wtsPath).exists()) wtsPath else null
                        ))
                        android.util.Log.d("HomeViewModel", "Updated vttPath for: ${video.title}")
                    }
                } catch (e: Exception) {
                    android.util.Log.e("HomeViewModel", "Failed to update vttPath", e)
                }
            }
        }
    }

    /**
     * 开始手动转录视频
     * 启动 TranscriptionService 进行转录
     */
    fun startTranscription(video: VideoEntity, context: Context) {
        viewModelScope.launch {
            try {
                // 启动转录服务
                val intent = Intent(context, com.multilanglearner.service.TranscriptionService::class.java).apply {
                    action = com.multilanglearner.service.TranscriptionService.ACTION_START
                    putExtra(com.multilanglearner.service.TranscriptionService.EXTRA_VIDEO_PATH, video.filePath)
                    putExtra(com.multilanglearner.service.TranscriptionService.EXTRA_VIDEO_NAME, video.title)
                }
                context.startForegroundService(intent)

                android.util.Log.d("HomeViewModel", "Started transcription for: ${video.title}")
            } catch (e: Exception) {
                android.util.Log.e("HomeViewModel", "Failed to start transcription", e)
            }
        }
    }
}

