package com.multilanglearner.data.db.dao

import androidx.room.*
import com.multilanglearner.data.db.entity.FavoriteWord
import kotlinx.coroutines.flow.Flow

@Dao
interface FavoriteDao {
    @Query("SELECT * FROM favorites ORDER BY created_at DESC")
    fun getAll(): Flow<List<FavoriteWord>>

    @Query("SELECT * FROM favorites WHERE lang = :lang ORDER BY created_at DESC")
    fun getByLang(lang: String): Flow<List<FavoriteWord>>

    @Query("SELECT EXISTS(SELECT 1 FROM favorites WHERE word = :word AND lang = :lang)")
    suspend fun isFavorite(word: String, lang: String): Boolean

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(word: FavoriteWord)

    @Query("DELETE FROM favorites WHERE word = :word AND lang = :lang")
    suspend fun delete(word: String, lang: String)

    @Query("DELETE FROM favorites WHERE id IN (:ids)")
    suspend fun deleteByIds(ids: List<Long>)

    @Query("UPDATE favorites SET box = :box WHERE id = :id")
    suspend fun setBox(id: Long, box: String)

    @Query("UPDATE favorites SET box = :box WHERE id IN (:ids)")
    suspend fun batchSetBox(ids: List<Long>, box: String)

    @Query("SELECT DISTINCT box FROM favorites WHERE box != '' ORDER BY box")
    suspend fun listBoxes(): List<String>

    @Insert(onConflict = OnConflictStrategy.IGNORE)
    suspend fun insertIgnore(word: FavoriteWord): Long
}

package com.multilanglearner.data.repository

import com.multilanglearner.data.db.dao.FavoriteDao
import com.multilanglearner.data.db.entity.FavoriteWord
import kotlinx.coroutines.flow.Flow
import javax.inject.Inject
import javax.inject.Singleton

@Singleton
class FavoriteRepository @Inject constructor(private val dao: FavoriteDao) {
    fun getAll(): Flow<List<FavoriteWord>> = dao.getAll()
    fun getByLang(lang: String): Flow<List<FavoriteWord>> = dao.getByLang(lang)
    suspend fun isFavorite(word: String, lang: String) = dao.isFavorite(word, lang)

    suspend fun add(word: String, lang: String, phonetic: String = "", translation: String = "", context: String = "") {
        dao.insert(FavoriteWord(word = word, lang = lang, phonetic = phonetic, translation = translation, context = context))
    }

    suspend fun remove(word: String, lang: String) = dao.delete(word, lang)
    suspend fun deleteByIds(ids: List<Long>) = dao.deleteByIds(ids)

    suspend fun importWords(words: List<String>, lang: String): Int {
        var count = 0
        for (w in words) {
            val trimmed = w.trim()
            if (trimmed.isNotEmpty()) {
                val result = dao.insertIgnore(FavoriteWord(word = trimmed, lang = lang))
                if (result != -1L) count++
            }
        }
        return count
    }

    suspend fun setBox(id: Long, box: String) = dao.setBox(id, box)
    suspend fun batchSetBox(ids: List<Long>, box: String) = dao.batchSetBox(ids, box)
    suspend fun listBoxes() = dao.listBoxes()
}

