                    // 并行查询
                    val onlineDeferred = kotlinx.coroutines.async { dictionaryService.lookupEnglish(word) }
                    val transDeferred = kotlinx.coroutines.async { dictionaryService.translate(word, "en") }
                    val aiDeferred = kotlinx.coroutines.async { aiTranslateWord(word, context, lang, aiConfig) }
                    val online = onlineDeferred.await()
                    val translation = transDeferred.await()
                    val aiTrans = aiDeferred.await()
                    WordCardData(
                        word = word,
                        phonetic = online?.phonetic ?: "",
                        translation = aiTrans ?: translation ?: online?.translation ?: "未找到释义",
                        definitions = online?.definitions ?: emptyList(),
                        examples = online?.examples ?: emptyList()
                    )
                }
                "ja" -> {
                    val onlineDeferred = kotlinx.coroutines.async { dictionaryService.lookupJapanese(word) }
                    val transDeferred = kotlinx.coroutines.async { dictionaryService.translate(word, "ja") }
                    val aiDeferred = kotlinx.coroutines.async { aiTranslateWord(word, context, lang, aiConfig) }
                    val online = onlineDeferred.await()
                    val translation = transDeferred.await()
                    val aiTrans = aiDeferred.await()
                    WordCardData(
                        word = word,
                        phonetic = online?.phonetic ?: "",
                        translation = aiTrans ?: translation ?: "未找到释义",
                        definitions = online?.definitions ?: emptyList()
                    )
                }
                else -> {
                    val transDeferred = kotlinx.coroutines.async { dictionaryService.translate(word, lang) }
                    val aiDeferred = kotlinx.coroutines.async { aiTranslateWord(word, context, lang, aiConfig) }
                    val translation = transDeferred.await()
                    val aiTrans = aiDeferred.await()
                    WordCardData(
                        word = word,
                        translation = aiTrans ?: translation ?: "未找到释义"
                    )
                }
            }
        } ?: WordCardData(word = word, translation = "查询超时，请检查网络")

        _uiState.update { it.copy(wordCardData = cardData) }
    }
}

